# Called by child class constructors
class SmartDriver(HPSmartBasicActions):
    def __init__(self, driver, timeout=10):
        super().__init__(driver)

# Verify print button is displayed
if self.element_displayed(self.print_button, timeout=60):
    self.click_element(self.print_button)

# Wait for element before clicking
if self.wait_for_object(self.home_page_ready, timeout=120):
    self.click_element(self.home_page_print_documents)

# Check if submit button is enabled before clicking
if self.wait_for_element_and_check_enabled(self.submit_button, timeout=30):
    self.click_element(self.submit_button)

previous_mode = ews.toggle_ip_mode_and_apply(timeout=60)
if previous_mode:
    print(f'Toggled from {previous_mode} mode')
